/* SPDX-License-Identifier: MIT
 * Secure memory‑handling example
 *
 * Mitigated CWEs:
 *   - CWE-131: Incorrect calculation of buffer size
 *   - CWE-120: Buffer copy without size check (overflow)
 *   - CWE-416: Use after free
 *   - CWE-762: Mismatched memory management routines
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

#define CHUNK_SIZE 10   /* exact size of each allocation, in bytes */

/* Helper: abort with a diagnostic message */
static void fatal(const char *msg) {
    perror(msg);
    exit(EXIT_FAILURE);
}

int main(void) {
    /* 1️⃣ Allocate the first chunk */
    unsigned char *chunk1 = malloc(CHUNK_SIZE);
    if (chunk1 == NULL) {
        fatal("malloc for chunk1 failed");
    }

    /* 2️⃣ Allocate the second chunk */
    unsigned char *chunk2 = malloc(CHUNK_SIZE);
    if (chunk2 == NULL) {
        /* Clean up the first allocation before exiting */
        free(chunk1);
        chunk1 = NULL;
        fatal("malloc for chunk2 failed");
    }

    /* 3️⃣ Initialise the first chunk (example payload) */
    for (size_t i = 0; i < CHUNK_SIZE; ++i) {
        chunk1[i] = (unsigned char)i;   /* deterministic data for demo */
    }

    /* 4️⃣ Safe copy: memcpy with explicit size = CHUNK_SIZE */
    memcpy(chunk2, chunk1, CHUNK_SIZE);
    /* No need for additional bounds checks – both buffers are exactly CHUNK_SIZE */

    /* 5️⃣ Use the copied data (demonstration) */
    printf("Chunk2 contents: ");
    for (size_t i = 0; i < CHUNK_SIZE; ++i) {
        printf("%02X ", chunk2[i]);
    }
    printf("\n");

    /* 6️⃣ Free resources – defensive pattern */
    free(chunk1);
    chunk1 = NULL;   /* prevent accidental use after free */

    free(chunk2);
    chunk2 = NULL;   /* prevent double‑free later in the program */

    return 0;
}
```

