        fprintf(stderr, "Error reading input.\n");
        return -1;
    }

    /* Strip trailing newline, if present */
    buf[strcspn(buf, "\n")] = '\0';

    /* Convert to long with error checking */
    errno = 0;
    idx_long = strtol(buf, &endptr, 10);

