    if (errno != 0 || endptr == buf || *endptr != '\0') {
        fprintf(stderr, "Invalid integer input.\n");
        return -1;
    }

    /* Ensure the value fits into size_t and is non‑negative */
    if (idx_long < 0 || (unsigned long)idx_long > SIZE_MAX) {
        fprintf(stderr, "Index out of range.\n");
        return -1;
    }
    idx = (size_t)idx_long;

    /* Bounds check against the actual array length */
    if (idx >= ID_SEQ_LEN) {
        fprintf(stderr, "Index %zu is out of bounds (max %zu).\n",
                idx, ID_SEQ_LEN - 1);
        return -1;
    }

    /* Safe access – the bounds check guarantees no overflow */
    return id_sequence[idx];
}

/*---------------------------------------------------------------*/
