{
    int result = get_id_at_index();

    if (result == -1) {
        /* An error was already reported inside the function */
        /* Exit code 1 signals failure to the caller/OS */
        return 1;
    }

    printf("Value at requested index: %d\n", result);
    return 0;   /* Success */
}
