 *           safe_lookup.c
 ********************************************************************/

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

/*---------------------------------------------------------------*/
/*  getValueFromArray
 *
 *  Parameters
 *      arr   – pointer to the first element of the integer array
 *      size  – number of elements in the array (must be > 0)
 *      idx   – index to read
 *
 *  Returns
 *      arr[idx]  if 0 <= idx < size
 *      -1        otherwise
 *---------------------------------------------------------------*/
static int getValueFromArray(const int *arr, size_t size, size_t idx)
{
    if (arr == NULL) {
        /* Defensive programming – should never happen in this program */
        return -1;
    }

    if (idx < size) {
        return arr[idx];
    }
    return -1;
}

/*---------------------------------------------------------------*/
/*  safe_exit
 *
 *  POSIX exit codes are limited to the low‑order 8 bits (0‑255).
 *  This helper maps any integer to that range without overflow.
 *---------------------------------------------------------------*/
static void safe_exit(int value)
{
    /* Map -1 (error) to 255, otherwise clamp to 0‑254 */
    unsigned int code;
    if (value == -1) {
        code = 255U;
    } else if (value < 0) {
        code = 0U;               /* Should not happen, but keep safe */
    } else if ((unsigned int)value > 254U) {
        code = 254U;             /* Truncate large positive values */
    } else {
        code = (unsigned int)value;
    }
    exit((int)code);
}

