int main(void)
{
    /* Example static array – in a real program this could be dynamic */
    const int data[] = {10, 20, 30, 40, 50};
    const size_t data_len = sizeof(data) / sizeof(data[0]);

    /* ---------- Read an integer from stdin safely ---------- */
    char line[64];
    if (fgets(line, sizeof(line), stdin) == NULL) {
        fprintf(stderr, "Error: no input received.\n");
        safe_exit(-1);
    }

    char *endptr = NULL;
    errno = 0;
    long idx_long = strtol(line, &endptr, 10);

    /* Detect conversion errors */
    if (errno != 0 || endptr == line || *endptr != '\n' && *endptr != '\0') {
        fprintf(stderr, "Error: invalid integer input.\n");
        safe_exit(-1);
    }

    /* Ensure the value fits into size_t (non‑negative and not overflow) */
    if (idx_long < 0 || (unsigned long)idx_long > SIZE_MAX) {
        fprintf(stderr, "Error: index out of range.\n");
        safe_exit(-1);
    }

    size_t index = (size_t)idx_long;

    /* ---------- Perform the lookup ---------- */
    int result = getValueFromArray(data, data_len, index);

    /* ---------- Return the result as a safe exit code ---------- */
    safe_exit(result);
}
