#include <stdio.h>
#include <string.h>
#include <errno.h>

/**
 * @brief Reads a line from stdin into `buf`.
 *
 * The function reads up to `bufsize‑1` characters, stops at the first
 * newline (which is consumed but not stored), and always NUL‑terminates
 * the buffer.  On success it returns the number of characters stored
 * (0‑based length).  On error it returns –1 and sets `errno` appropriately.
 *
 * @param buf      Destination buffer (must be at least `bufsize` bytes).
 * @param bufsize  Total size of `buf` (must be ≥ 2; we expect 1024).
 *
 * @return Number of characters stored on success, –1 on error/EOF.
 */
int safe_scan(char *buf, size_t bufsize)
{
    if (buf == NULL || bufsize < 2) {
        errno = EINVAL;               /* invalid argument */
        return -1;
    }

    /* fgets reads at most bufsize‑1 characters and always NUL‑terminates. */
    if (fgets(buf, (int)bufsize, stdin) == NULL) {
        /* fgets returns NULL on EOF or error – preserve errno. */
        return -1;
    }

    /* At this point buf contains either:
     *   – a full line ending with '\n', or
     *   – a truncated line without '\n' (input longer than bufsize‑1).
     */

    size_t len = strlen(buf);

    /* If the line ended with a newline, strip it and discard it. */
    if (len > 0 && buf[len - 1] == '\n') {
        buf[--len] = '\0';            /* remove newline, keep NUL terminator */
    }

    /* If the newline was not present, the input was longer than the buffer.
     * The excess characters remain in the stdin stream; we discard them
     * safely to keep the stream in a known state for subsequent reads.
     */
    if (len == bufsize - 1 && buf[len - 1] != '\n') {
        int ch;
        /* Consume until newline or EOF. */
        while ((ch = getchar()) != '\n' && ch != EOF) {
            /* no‑op – just discarding */
        }
        /* If EOF was reached, errno is already set by getchar(). */
    }

    return (int)len;                  /* number of characters stored */
}

/* --------------------------------------------------------------------- */
/* Example usage (can be removed in production code)                     */
