int main(void)
{
    char input[1024];                 /* 1024‑byte buffer as required */

    printf("Enter a line (max 1023 chars): ");
    fflush(stdout);

    int n = safe_scan(input, sizeof(input));
    if (n < 0) {
        perror("safe_scan failed");
        return 1;
    }

    printf("You entered %d character(s): \"%s\"\n", n, input);
    return 0;
}
#endif
/* --------------------------------------------------------------------- */
