/*
 * Secure creation of "important_config" with owner‑only permissions.
 * Compiles with: gcc -Wall -Wextra -O2 -std=c11 secure_create.c -o secure_create
 */

#define _POSIX_C_SOURCE 200809L   /* for O_NOFOLLOW, fchmod, etc. */

#include <fcntl.h>
#include <unistd.h>
#include <sys/stat.h>
#include <stdio.h>
#include <errno.h>
#include <string.h>

