/*
 * Secure example: safe array lookup with validated input.
 * SPDX‑License-Identifier: MIT
 *
 * Build:   gcc -Wall -Wextra -pedantic -O2 -std=c11 -o safe_lookup safe_lookup.c
 * Run:     ./safe_lookup
 *
 * The program reads an integer index from stdin, looks up the value in a
 * static integer array, prints the value (or an error message) and exits
 * with a status code in the range 0‑255.
 */

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <limits.h>

/* --------------------------------------------------------------------- */
/*  Constants & data                                                    */
/* --------------------------------------------------------------------- */
static const int id_sequence[] = { 10, 20, 30, 40, 50 };
static const size_t ID_SEQUENCE_SIZE = sizeof(id_sequence) / sizeof(id_sequence[0]);

/* --------------------------------------------------------------------- */
/*  Helper: safe conversion from string to long (base‑10)                */
/* --------------------------------------------------------------------- */
static int parse_int(const char *input, int *out_value)
{
    char *endptr = NULL;
    long val;

    errno = 0;
    val = strtol(input, &endptr, 10);

    /* Detect conversion errors */
    if (errno != 0 || endptr == input || *endptr != '\0')
        return -1;                     /* malformed number */

    /* Ensure the value fits into a signed int */
    if (val < INT_MIN || val > INT_MAX)
        return -1;                     /* out of range */

    *out_value = (int)val;
    return 0;                          /* success */
}

/* --------------------------------------------------------------------- */
/*  Core logic: bounded array access                                    */
/* --------------------------------------------------------------------- */
static int getValueFromArray(const int *arr, size_t size, int index)
{
    if (index < 0 || (size_t)index >= size)
        return -1;                     /* out‑of‑bounds sentinel */

    return arr[index];
}

/* --------------------------------------------------------------------- */
/*  Main entry point                                                    */
/* --------------------------------------------------------------------- */
int main(void)
{
    char line[64];
    int index;
    int result;
    int exit_status = 0;               /* default success */

    /* Prompt the user (optional – can be removed for non‑interactive use) */
    if (printf("Enter array index (0‑%zu): ", ID_SEQUENCE_SIZE - 1) < 0) {
        perror("printf");
        return 1;
    }
    fflush(stdout);

    /* Read a line from stdin – safe against overflow */
    if (fgets(line, sizeof(line), stdin) == NULL) {
        fprintf(stderr, "Error: failed to read input.\n");
        return 1;
    }

    /* Strip trailing newline, if present */
    line[strcspn(line, "\n")] = '\0';

    /* Validate and convert the input */
    if (parse_int(line, &index) != 0) {
        fprintf(stderr, "Error: invalid integer input.\n");
        exit_status = 2;               /* user‑input error */
        goto finish;
    }

    /* Perform the bounded lookup */
    result = getValueFromArray(id_sequence, ID_SEQUENCE_SIZE, index);
    if (result == -1) {
        fprintf(stderr, "Error: index out of bounds.\n");
        exit_status = 3;               /* logical error */
    } else {
        printf("Value at index %d is %d\n", index, result);
        /* The program’s *semantic* success is indicated by exit_status = 0 */
    }

finish:
    /*
     * POSIX exit codes are limited to the low‑order 8 bits (0‑255).
     * We explicitly clamp the status to that range to avoid undefined
     * behaviour on platforms where larger values are truncated.
     */
    if (exit_status < 0)   exit_status = 0;
    if (exit_status > 255) exit_status = 255;

    return exit_status;
}
```

