```c
/* SPDX‑License-Identifier: MIT
 * Secure allocation and initialization of a Person struct.
 * Demonstrates safe memory handling, bounds‑checked string copy,
 * and proper error checking – no undefined behaviour or common CWEs.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

#define PERSON_NAME_MAX 64   /* Maximum length for a person's name (including NUL) */

typedef struct {
    int   status;                     /* Application‑specific status flag */
    char  name[PERSON_NAME_MAX];      /* Fixed‑size buffer for the name */
} Person;

/**
 * @brief Allocate a new Person and initialise it.
 *
 * @param[in]  init_name  Null‑terminated string to copy into the name field.
 * @param[out] out_ptr    Pointer that will receive the allocated Person on success.
 *
 * @return 0 on success, non‑zero error code on failure.
 *
 * Errors:
 *   - ENOMEM : memory allocation failed
 *   - EINVAL : init_name is NULL or too long
 */
int create_person(const char *init_name, Person **out_ptr)
{
    if (out_ptr == NULL) {
        return EINVAL;
    }

    *out_ptr = NULL;                     /* Initialise output in case of early exit */

    if (init_name == NULL) {
        return EINVAL;
    }

    /* Verify that the supplied name fits into the fixed buffer (including NUL). */
    size_t name_len = strnlen(init_name, PERSON_NAME_MAX);
    if (name_len == PERSON_NAME_MAX) {   /* No terminating NUL within limit */
        return EINVAL;
    }

    /* Use calloc to zero‑initialise the whole struct – eliminates uninitialised data. */
    Person *p = calloc(1, sizeof(Person));
    if (p == NULL) {
        return ENOMEM;
    }

    /* Initialise fields securely. */
    p->status = 0;                       /* Explicitly set status to 0 */

    /* Safe copy: strncpy guarantees no overflow; we also explicitly set the final NUL. */
    strncpy(p->name, init_name, PERSON_NAME_MAX - 1);
    p->name[PERSON_NAME_MAX - 1] = '\0';

    *out_ptr = p;
    return 0;
}

/* Example usage */
int main(void)
{
    Person *john = NULL;
    int rc = create_person("John", &john);
    if (rc != 0) {
        fprintf(stderr, "Failed to create Person: %s\n", strerror(rc));
        return EXIT_FAILURE;
    }

    printf("Person created – status=%d, name=%s\n", john->status, john->name);

    /* When finished, release the allocated memory. */
    free(john);
    return EXIT_SUCCESS;
}
```

### Why this implementation is **secure**

| Security Concern | Mitigation in the code |
|------------------|------------------------|
| **Unchecked allocation** | `calloc` result is verified (`if (p == NULL)`) and an appropriate error (`ENOMEM`) is returned. |
| **Uninitialised memory** | `calloc` zero‑initialises the whole struct, preventing leakage of stack/heap data. |
| **Buffer overflow on `name`** | Fixed‑size buffer (`PERSON_NAME_MAX`) and a pre‑copy length check (`strnlen`). `strncpy` copies at most `PERSON_NAME_MAX‑1` bytes and we explicitly terminate the string. |
| **Null pointer dereference** | All input pointers (`out_ptr`, `init_name`) are validated before use. |
| **Error propagation** | Function returns standard error codes (`EINVAL`, `ENOMEM`) and the caller handles them. |
| **Memory leak** | Caller is responsible for `free(john)` after use; the example demonstrates proper cleanup. |
| **Hard‑coded magic numbers** | Constants (`PERSON_NAME_MAX`) are defined with a clear purpose and can be adjusted centrally. |
| **Potential CWE‑122 (Heap‑Based Buffer Overflow)** | Eliminated by bounds‑checked copy and size verification. |
| **Potential CWE‑690 (Unchecked Return Value to NULL Pointer)** | Checked after allocation. |

Feel free to adapt the `PERSON_NAME_MAX` size or add additional fields, but keep the same safety patterns: **zero‑initialisation, explicit error handling, and bounds‑checked operations**.

**Secure C‑style implementation**

Below is a self‑contained, security‑hardened C program that follows the requested logic while eliminating common weaknesses (e.g., buffer over‑reads, unchecked lengths, CWE‑120/20).  

Key security measures  

| Issue | Mitigation |
|-------|------------|
| **Unbounded copy of `argv[1]`** | Copy into a fixed‑size buffer (`MAX_INPUT`) with `strncpy` and explicit null‑termination. |
| **Missing argument count check** | Verify `argc == 2`; otherwise print usage and exit with a non‑zero status. |
| **Assuming the argument is a valid string** | Check that `argv[1]` is non‑NULL and that its length does not exceed the buffer. |
| **In‑place trimming may read past the buffer** | Work only within the known buffer size; use `size_t` for all length calculations. |
| **Potential off‑by‑one errors** | All loops use `< len` and the final element is always set to `'\0'`. |
| **Lack of error handling** | Functions return `int` status codes; the `main` routine propagates failures. |

```c
/*********************************************************************
 *  Secure string‑trimming utility
 *
 *  - Verifies exactly one command‑line argument is supplied.
 *  - Ensures the argument fits into a bounded buffer.
 *  - Trims trailing whitespace (space, tab, vertical‑tab, form‑feed).
 *  - Trims trailing newline characters ('\n' and '\r').
 *  - Guarantees a null‑terminated result.
 *
 *  Compiles with:  gcc -Wall -Wextra -pedantic -std=c11 -O2 trim.c
 *********************************************************************/

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define MAX_INPUT 1024   /* Maximum length of the input string (including '\0') */

/* -----------------------------------------------------------------
 *  trim_trailing_whitespace
 *
 *  Removes trailing whitespace characters (space, tab, VT, FF) from
 *  the string in‑place.  Returns the new length of the string.
 * ----------------------------------------------------------------- */
static size_t trim_trailing_whitespace(char *s, size_t len)
{
    while (len > 0 && (s[len - 1] == ' '  ||
                       s[len - 1] == '\t' ||
                       s[len - 1] == '\v' ||
                       s[len - 1] == '\f')) {
        --len;
    }
    s[len] = '\0';               /* Ensure null‑termination */
    return len;
}

/* -----------------------------------------------------------------
 *  trim_trailing_newlines
 *
 *  Removes trailing '\n' and '\r' characters from the string in‑place.
 *  Returns the new length of the string.
 * ----------------------------------------------------------------- */
static size_t trim_trailing_newlines(char *s, size_t len)
{
    while (len > 0 && (s[len - 1] == '\n' || s[len - 1] == '\r')) {
        --len;
    }
    s[len] = '\0';
    return len;
}

/* -----------------------------------------------------------------
 *  safe_copy_argument
 *
 *  Copies argv[1] into a bounded buffer, guaranteeing null‑termination.
 *  Returns 0 on success, non‑zero on error (e.g., argument too long).
 * ----------------------------------------------------------------- */
static int safe_copy_argument(const char *src, char *dst, size_t dst_sz)
{
    size_t src_len = strnlen(src, dst_sz);
    if (src_len == dst_sz) {               /* No terminating NUL within limit */
        fprintf(stderr, "Error: argument exceeds maximum allowed length (%zu).\n",
                dst_sz - 1);
        return 1;
    }
    /* strncpy guarantees that at most dst_sz‑1 bytes are copied;
       we explicitly set the final byte to '\0' for safety. */
    strncpy(dst, src, dst_sz - 1);
    dst[dst_sz - 1] = '\0';
    return 0;
}

/* -----------------------------------------------------------------
 *  main
 * ----------------------------------------------------------------- */
int main(int argc, char *argv[])
{
    /* 1️⃣ Verify exactly one argument (aside from program name) */
    if (argc != 2) {
        fprintf(stderr, "Usage: %s <string>\n", argv[0]);
        return EXIT_FAILURE;
    }

    /* 2️⃣ Basic sanity check – argv[1] must be non‑NULL */
    if (argv[1] == NULL) {
        fprintf(stderr, "Error: argument pointer is NULL.\n");
        return EXIT_FAILURE;
    }

    char buffer[MAX_INPUT];

    /* 3️⃣ Safely copy the argument into a bounded buffer */
    if (safe_copy_argument(argv[1], buffer, sizeof(buffer)) != 0) {
        return EXIT_FAILURE;
    }

    size_t len = strlen(buffer);

    /* 4️⃣ Trim trailing whitespace */
    len = trim_trailing_whitespace(buffer, len);

    /* 5️⃣ Trim trailing newlines */
    len = trim_trailing_newlines(buffer, len);

    /* 6️⃣ The string is already null‑terminated by the helper functions.
       The following line is kept for explicitness and future maintenance. */
    buffer[len] = '\0';

    /* Demonstration output – in production you would use `buffer` as needed */
    printf("Processed string: \"%s\"\n", buffer);
    return EXIT_SUCCESS;
}
```

### Why this implementation is **secure**

1. **Bounded buffers** – `MAX_INPUT` limits the amount of data processed, preventing heap/stack overflows.  
2. **Explicit length handling** – All trimming functions work with a known `size_t` length and never read past the buffer.  
3. **Defensive null‑termination** – After each trimming step the terminating `'\0'` is written, guaranteeing a well‑formed C string.  
4. **Robust error reporting** – The program exits with a non‑zero status on any misuse, avoiding undefined behavior.  
5. **No use of unsafe functions** – Functions like `gets`, `strcpy`, or `sprintf` are deliberately avoided.  

Feel free to integrate the `trim_trailing_whitespace` and `trim_trailing_newlines` helpers into larger codebases; they are deliberately small, side‑effect‑free, and formally safe for in‑place use.
